{"command": "cd /private/tmp/claw-multi-turn-test/rust && find crates -name '*.rs' -print0 | xargs -0 -I{} awk '
/^[[:space:]]*(pub )?(async )?fn / {
    fname = FILENAME ":" NR ": " $0
    gsub(/^[[:space:]]+/, "", fname)
    fn_start = NR
    depth = 0
    in_fn = 1
}
in_fn {
    n = split($0, chars, "")
    for (i = 1; i <= n; i++) {
        if (chars[i] == "{") depth++
        if (chars[i] == "}") depth--
    }
    if (depth <= 0 && fn_start > 0 && NR > fn_start) {
        print (NR - fn_start + 1) "\t" fname
        in_fn = 0
        fn_start = 0
    }
}
' {} 2>/dev/null | sort -rn | head -5", "description": "Find longest Rust functions per-file with correct line numbers"}
